mapper.select:
SELECT EXISTS(
  SELECT 1
  FROM reservation
  WHERE product_id = #{productId}
    AND reserved_date = #{reservedDate}
    AND (
      (#{startTime} IS NULL AND start_time IS NULL)
      OR start_time = #{startTime}
    )
    AND status IN ('PENDING','CONFIRMED')
)

mapper.update:
UPDATE reservation
SET status = #{status}
WHERE id = #{id}
